import React from "react";
import {Modal, Pressable, StyleSheet, View} from "react-native";
import Animated, {FadeIn, ZoomIn} from "react-native-reanimated";
import {Icon, Text} from "../../../";
import type {IConfirmDialogProps} from "@lmb/kitsconcerto-types";
import {useKitsTheme} from "../../../Contexts/Theme";
import {useSeverityColors, useAllSeverityColors} from "../../../Hooks/useSeverityColors";

export default function KitsConfirm(props: IConfirmDialogProps) {
    const {
        visible,
        header,
        message,
        icon,
        type = "secondary",
        accept,
        reject,
        acceptLabel = "Accept",
        rejectLabel = "Reject",
        buttons,
        headless,
        defaultUI,
        async: asyncMode,
        onHide,
        content,
        children,
        ...rest
    } = props;

    const {resolveToken, theme} = useKitsTheme();
    const colors = useSeverityColors(type);
    const allColors = useAllSeverityColors();

    const surfaceColor = resolveToken('surface-card');
    const textColor = resolveToken('text');
    const subtextColor = resolveToken('gray.500');
    const brandLogo = type === 'brand' ? theme.config.logo : null;

    if (!visible) return null;

    const hide = () => onHide?.('hide');

    const doClick = async (callback?: () => void) => {
        if (asyncMode) {
            await callback?.();
            hide();
        } else {
            hide();
            callback?.();
        }
    };

    const showIcon = icon != null || brandLogo != null;
    const panelBg = type !== 'secondary' ? colors.bgTint : surfaceColor;

    // Content-only mode (prompt)
    if (content) {
        return (
            <Modal visible transparent animationType="none" onRequestClose={hide}>
                <Animated.View entering={FadeIn.duration(200)} style={styles.overlay}>
                    <Pressable style={StyleSheet.absoluteFill} onPress={hide}/>
                    <Animated.View
                        entering={ZoomIn.springify().damping(40).stiffness(300)}
                        style={[styles.panel, {backgroundColor: surfaceColor}]}
                    >
                        {content as React.ReactNode}
                    </Animated.View>
                </Animated.View>
            </Modal>
        );
    }

    return (
        <Modal visible transparent animationType="none" onRequestClose={hide}>
            <Animated.View entering={FadeIn.duration(200)} style={styles.overlay}>
                <Pressable style={StyleSheet.absoluteFill} onPress={hide}/>

                {/* Card + icon stack: icon sits above the card */}
                <View style={styles.cardStack}>
                    {/* Soft-circle icon bubble */}
                    {showIcon && (
                        <Animated.View
                            entering={ZoomIn.springify().damping(60).stiffness(500).delay(100)}
                            style={[styles.iconBubble, {backgroundColor: colors.iconBg}]}
                        >
                            {brandLogo ? brandLogo : typeof icon === "string" ? (
                                <Icon name={icon as never} size={'xl'} color={colors.iconFg}/>
                            ) : (
                                icon
                            )}
                        </Animated.View>
                    )}

                    {/* Panel */}
                    <Animated.View
                        entering={ZoomIn.springify().damping(60).stiffness(500)}
                        style={[
                            styles.panel,
                            {
                                backgroundColor: panelBg,
                                paddingTop: showIcon ? 48 : 24,
                                gap: 10,
                            },
                        ]}
                    >
                        {/* Close button */}
                        <Pressable style={styles.closeBtn} onPress={hide} hitSlop={12}>
                            <Text style={{fontSize: 18, color: subtextColor}}>✕</Text>
                        </Pressable>

                        {/* Header */}
                        {header != null && (
                            <Text style={[styles.header, {color: textColor}]}>
                                {header as React.ReactNode}
                            </Text>
                        )}

                        {/* Message */}
                        {message != null && (
                            <Text style={[styles.message, {color: subtextColor}]}>
                                {message as React.ReactNode}
                            </Text>
                        )}

                        {/* Children */}
                        {children}

                        {/* Buttons */}
                        <View style={styles.buttonRow}>
                            {buttons?.length ? (
                                buttons.map((b, i) => {
                                    const btnColor = allColors[b.type ?? type]?.solid ?? colors.solid;
                                    return (
                                        <Pressable
                                            key={i}
                                            disabled={b.disabled}
                                            style={[
                                                styles.actionBtn,
                                                b.outlined
                                                    ? {backgroundColor: "transparent", borderColor: btnColor, borderWidth: 1.5}
                                                    : {backgroundColor: btnColor},
                                                b.rounded && {borderRadius: 999},
                                                b.disabled && {opacity: 0.5},
                                            ]}
                                            onPress={() => b.onClick(hide, accept, reject)}
                                        >
                                            <Text style={{
                                                color: b.outlined ? btnColor : "#fff",
                                                fontWeight: "600",
                                                fontSize: 14,
                                            }}>
                                                {b.title}
                                            </Text>
                                        </Pressable>
                                    );
                                })
                            ) : (
                                <>
                                    <Pressable
                                        style={[styles.actionBtn, {backgroundColor: colors.solid, flex: 1}]}
                                        onPress={() => doClick(accept)}
                                    >
                                        <Text style={styles.btnTextPrimary}>{acceptLabel}</Text>
                                    </Pressable>
                                    {!defaultUI && (
                                        <Pressable
                                            style={[styles.actionBtn, styles.actionBtnOutlined, {borderColor: colors.solid, flex: 1}]}
                                            onPress={() => doClick(reject)}
                                        >
                                            <Text style={[styles.btnTextOutlined, {color: colors.solid}]}>
                                                {rejectLabel}
                                            </Text>
                                        </Pressable>
                                    )}
                                </>
                            )}
                        </View>
                    </Animated.View>
                </View>
            </Animated.View>
        </Modal>
    );
}

const styles = StyleSheet.create({
    overlay: {
        flex: 1,
        backgroundColor: "rgba(0,0,0,0.45)",
        justifyContent: "center",
        alignItems: "center",
        padding: 28,
    },
    cardStack: {
        width: "100%",
        maxWidth: 380,
        alignItems: "center",
    },
    iconBubble: {
        width: 72,
        height: 72,
        borderRadius: 36,
        justifyContent: "center",
        alignItems: "center",
        zIndex: 2,
        marginBottom: -36,
        elevation: 8,
        shadowColor: "#000",
        shadowOffset: {width: 0, height: 4},
        shadowOpacity: 0.15,
        shadowRadius: 8,
    },
    panel: {
        width: "100%",
        borderRadius: 16,
        paddingHorizontal: 24,
        paddingBottom: 24,
        elevation: 16,
        shadowColor: "#000",
        shadowOffset: {width: 0, height: 8},
        shadowOpacity: 0.2,
        shadowRadius: 16,
        alignItems: "center",
    },
    closeBtn: {
        position: "absolute",
        top: 12,
        right: 14,
        zIndex: 3,
    },
    header: {
        fontSize: 22,
        fontWeight: "700",
        textAlign: "center",
        marginBottom: 8,
    },
    message: {
        fontSize: 14,
        textAlign: "center",
        lineHeight: 20,
        marginBottom: 24,
    },
    buttonRow: {
        flexDirection: "row",
        justifyContent: "center",
        gap: 12,
        width: "100%",
    },
    actionBtn: {
        paddingVertical: 12,
        paddingHorizontal: 24,
        borderRadius: 8,
        minWidth: 100,
        alignItems: "center",
    },
    actionBtnOutlined: {
        backgroundColor: "transparent",
        borderWidth: 1.5,
    },
    btnTextPrimary: {
        color: "#fff",
        fontWeight: "600",
        fontSize: 14,
    },
    btnTextOutlined: {
        fontWeight: "600",
        fontSize: 14,
    },
});
